VALUES
  ('optometrist-moex-03634', 'optometrist', 'optometrist-moex-106-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '關於軟式隱形眼鏡的水膠和矽水膠材質敘述，下列何者錯誤？', '["水膠鏡片的透氧率和含水量成正相關", "矽水膠鏡片的透氧率和含矽量成正相關，較不受含水量影響", "水膠鏡片材料中交聯物質（cross-linker）增加時，材質的硬度將提高", "矽水膠鏡片材料中含矽量增加時，材質厭水性減低"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:56+00:00", "source_pdf_sha1": "43136df1aeb4", "answer_pdf_sha1": "f9cf08f73c11", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "112", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-03635', 'optometrist', 'optometrist-moex-106-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '關於氧流量（oxygen flux）的敘述，下列何者正確？', '["氧流量的計算不需要Dk/L值及鏡片前面與後面的壓力", "氧流量不代表有多少氧氣可抵達角膜 × -9 × × ×", "當矽水膠隱形眼鏡鏡片傳氧率（Dk/L, oxygen transmissibility）是80 10 (cm mL O)/(mL s mmHg)以 2 上，代表氧流量（張開眼時）至少都有95%以上，配戴日戴型矽水膠隱形眼鏡，不必擔心角膜缺氧問題", "氧流量即透氧率除以鏡片厚度"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:56+00:00", "source_pdf_sha1": "43136df1aeb4", "answer_pdf_sha1": "f9cf08f73c11", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "112", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-03636', 'optometrist', 'optometrist-moex-106-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '硬式隱形眼鏡材料單體有甲基丙烯酸甲酯（methyl methacrylate, MMA）、矽丙烯酸酯（silicone/acrylate）、 氟矽丙烯酸酯（fluoro-silicone/acrylate）。關於上述三種硬式隱形眼鏡材料特性的說明，下列何者錯誤？', '["相較於其他兩種材料，聚甲基丙烯酸甲酯（polymethylmethacrylate, PMMA）材料透氧率最差", "相較於其他兩種材料，矽丙烯酸酯製成之鏡片透氧率高且可抗油脂沉澱", "相較於其他兩種材料，氟矽丙烯酸酯製成之鏡片透氧率高且可抗沉澱", "若為夜戴式鏡片（overnight wear），選擇氟矽丙烯酸酯製成之鏡片較聚甲基丙烯酸甲酯鏡片為佳"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:56+00:00", "source_pdf_sha1": "43136df1aeb4", "answer_pdf_sha1": "f9cf08f73c11", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "112", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-03637', 'optometrist', 'optometrist-moex-106-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '關於隱形眼鏡保養與清潔步驟，下列敘述何者錯誤？', '["摘取或配戴隱形眼鏡前，應先以不含保濕乳霜成分的清潔液，徹底清潔雙手", "配戴隱形眼鏡後再化妝，卸除隱形眼鏡後再卸妝；可減少鏡片受到化妝品或卸妝產品染污的可能性", "鏡片保存盒不使用時，應注滿清潔液後緊蓋保存", "隱形眼鏡相關清潔護理液應注意保存期限，並隨時蓋緊以免染污"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:56+00:00", "source_pdf_sha1": "43136df1aeb4", "answer_pdf_sha1": "f9cf08f73c11", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "112", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-03638', 'optometrist', 'optometrist-moex-106-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '關於隱形眼鏡的多功能清潔護理液（multipurpose solution）添加成分，下列敘述何者錯誤？', '["添加保存劑（preservatives）可達殺菌或抑菌效果", "添加表面活性劑（surfactants）可增加鏡片配戴時的表面活性與帶電性", "添加保濕物質（wetting agents）可保持鏡片含水量", "做為緩衝液（buffer solution）可維持鏡片清潔與浸泡過程的酸鹼值穩定"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:56+00:00", "source_pdf_sha1": "43136df1aeb4", "answer_pdf_sha1": "f9cf08f73c11", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "112", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-03639', 'optometrist', 'optometrist-moex-106-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '關於隱形眼鏡的清潔殺菌，雙氧水（hydrogen peroxide）清潔液較多功能清潔護理液的優缺點敘述，何者 錯誤？', '["雙氧水清潔液對於病毒或黴菌的殺菌效果較多功能清潔護理液佳", "雙氧水清潔液即使未完全分解中和，配戴鏡片時也不會對眼表有化學刺激", "雙氧水清潔液需要足夠長的鏡片浸泡時間才能達到充分殺菌效果", "雙氧水清潔液無添加防腐劑，因此較無引起鏡片變色的可能"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:56+00:00", "source_pdf_sha1": "43136df1aeb4", "answer_pdf_sha1": "f9cf08f73c11", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "112", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-03640', 'optometrist', 'optometrist-moex-106-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '隱形眼鏡保養液中使用硼酸鹽（borates）或檸檬酸鹽（citrates）的作用為：', '["表面活性劑（surfactants）", "緩衝劑（buffer agents）", "保存劑（preservatives）", "螯合劑（chelating agents）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:56+00:00", "source_pdf_sha1": "43136df1aeb4", "answer_pdf_sha1": "f9cf08f73c11", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "112", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-03641', 'optometrist', 'optometrist-moex-106-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '關於硬式隱形眼鏡鏡片直徑（lens diameter）與光學區（optical zone）的敘述，下列何者錯誤？', '["鏡片光學區大小若可覆蓋微光下瞳孔直徑，能減少夜間眩光（glare）問題", "基弧（base curve）較平的鏡片，直徑需加大；基弧較陡的鏡片，直徑要縮小，才能得到較好的鏡片定位", "加大隱形眼鏡直徑，可增加眼皮對鏡片的作用力；縮小隱形眼鏡直徑，可減少眼皮對鏡片的作用力", "瞼裂（palpebral fissure）大者鏡片直徑要大，瞼裂小者鏡片直徑要小，鏡緣貼齊上下眼瞼緣，配戴舒適 度較佳"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:56+00:00", "source_pdf_sha1": "43136df1aeb4", "answer_pdf_sha1": "f9cf08f73c11", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "112", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-03642', 'optometrist', 'optometrist-moex-106-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '關於硬式隱形眼鏡邊弧（peripheral curve, peripheral curve radius）設計，下列敘述何者錯誤？', '["邊挑（edge lift）少，淚水交換少", "邊挑多，鏡片滑動大", "邊挑多，會增加上眼皮對鏡片抓力，使鏡片往上移動", "邊挑少，會減少下眼皮對鏡片抓力，使鏡片往上移動"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:56+00:00", "source_pdf_sha1": "43136df1aeb4", "answer_pdf_sha1": "f9cf08f73c11", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "112", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-03643', 'optometrist', 'optometrist-moex-106-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '硬式隱形眼鏡鏡片基弧、直徑與鏡片矢高（sagittal height）的相關性敘述，下列何者錯誤？', '["鏡片直徑不變，放平基弧，則鏡片相對變鬆，鏡片滑動增加", "鏡片基弧不變，加大直徑，則鏡片相對變緊，鏡片滑動減少", "鏡片直徑不變，放平基弧，則鏡片矢高增加", "鏡片基弧不變，加大直徑，則鏡片矢高增加"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:56+00:00", "source_pdf_sha1": "43136df1aeb4", "answer_pdf_sha1": "f9cf08f73c11", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "112", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL)
